const DB = {
  get(key, def){ try{ const v = localStorage.getItem(key); return v===null? def : JSON.parse(v); }catch(e){ return def; } },
  set(key, val){ localStorage.setItem(key, JSON.stringify(val)); }
};
const uid = () => Date.now().toString(36)+Math.random().toString(36).slice(2,7);
const RP = n => 'Rp' + Number(n||0).toLocaleString('id-ID');
const esc = s => String(s??'').replace(/[&<>"']/g, c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const todayISO = () => new Date().toISOString().slice(0,10);
const fmtDate = d => new Date(d).toLocaleDateString('id-ID',{day:'2-digit',month:'short',year:'numeric'});
/* Warna aksen per kategori untuk ilustrasi gambar cadangan produk */
const catAccent = kategoriId => ({1:'#F5A623',2:'#E64A3F',3:'#DB8A0B',4:'#4C7A3D',5:'#9E1E23',6:'#C1440E'}[kategoriId] || '#C1440E');
/* Render gambar produk: pakai foto asli jika admin sudah upload, kalau belum tampilkan ilustrasi bergradasi + emoji sebagai gambar cadangan */
function productMedia(p, boxClass, emojiClass){
  if(p.gambar) return `<img src="${p.gambar}" alt="${esc(p.nama)}" class="${boxClass} object-cover">`;
  const c = catAccent(p.kategoriId);
  return `<div class="${boxClass} relative flex items-center justify-center overflow-hidden" style="background:radial-gradient(circle at 18% 15%,${c}55,transparent 42%),radial-gradient(circle at 88% 82%,${c}38,transparent 45%),radial-gradient(circle at 55% 45%,#ffffffa8,transparent 60%),linear-gradient(160deg,#FBF3E4,#F5E4C4);">
    <span class="absolute inset-0 opacity-[.18]" style="background-image:radial-gradient(${c} 1.4px, transparent 1.4px);background-size:13px 13px;"></span>
    <span class="relative ${emojiClass}" style="filter:drop-shadow(0 3px 3px rgba(36,31,27,.25))">${p.emoji||'🍪'}</span>
  </div>`;
}
/* Password input with show/hide eye toggle */
function pwInput(name, placeholder, extraClass){
  return `<div class="relative ${extraClass||''}">
    <input required type="password" name="${name}" placeholder="${placeholder}" class="w-full border-2 border-paper-dark rounded-xl px-4 py-2.5 pr-11 focus:border-chili outline-none">
    <button type="button" tabindex="-1" onclick="Actions.togglePw(this)" aria-label="Tampilkan/Sembunyikan Password" class="absolute right-2 top-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center text-coffee-light hover:text-chili">
      <svg class="eye-open" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M1 12s4-7 11-7 11 7 11 7-4 7-11 7-11-7-11-7Z"/><circle cx="12" cy="12" r="3"/></svg>
      <svg class="eye-closed hidden" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M17.94 17.94A10.94 10.94 0 0 1 12 20c-7 0-11-8-11-8a19.7 19.7 0 0 1 5.06-6.06M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a19.87 19.87 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"/><path d="M1 1l22 22"/></svg>
    </button>
  </div>`;
}

