// Perbaikan otomatis: pastikan akun admin selalu ada meskipun localStorage browser
// masih menyimpan data lama dari versi sebelum akun admin ditambahkan/diperbarui.
// Migrasi ini hanya berjalan SEKALI (ditandai flag as_admin_migrated_v3) supaya tidak menimpa
// password baru yang sudah diganti admin sendiri lewat menu Ubah Password / Lupa Password.
(function ensureAdminAccount(){
  const CANONICAL = { nama:'Admin Aniez', email:'adminaniezsnack26@gmail.com', password:'admin1023', hp:'081298765432', foto:'🧑‍💼' };
  let admins = DB.get('as_admins', []);
  const alreadyMigrated = DB.get('as_admin_migrated_v3', false);

  if(!alreadyMigrated){
    // buang semua akun admin versi lama (email/password sebelumnya) yang tersimpan dari sesi sebelumnya
    admins = admins.filter(a=>a.email && a.email.toLowerCase()===CANONICAL.email.toLowerCase());
    const existing = admins[0];
    if(!existing){ admins.push({ id:1, ...CANONICAL }); }
    else { Object.assign(existing, CANONICAL, { id: existing.id }); }
    DB.set('as_admins', admins);
    DB.set('as_admin_migrated_v3', true);
    return;
  }

  // setelah migrasi, cukup pastikan minimal ada satu akun admin (jangan sampai kosong)
  if(admins.length===0){
    DB.set('as_admins', [{ id:1, ...CANONICAL }]);
  }
})();

