const PAYMENT_INFO = {
  'OVO': '🟣 Transfer/top up ke OVO <b>0812-3456-7890</b> a.n. Aniez Snack, lalu unggah bukti pembayaran.',
  'DANA': '🔵 Transfer ke DANA <b>0812-3456-7890</b> a.n. Aniez Snack, lalu unggah bukti pembayaran.',
  'Transfer Bank': '🏦 Transfer ke BCA <b>1234567890</b> a.n. Aniez Snack, lalu unggah bukti transfer.'
};
Actions.handleBuktiUpload = function(e){
  const file = e.target.files[0];
  if(!file) return;
  const reader = new FileReader();
  reader.onload = function(ev){
    const img = new Image();
    img.onload = function(){
      const maxW = 500;
      const scale = Math.min(1, maxW/img.width);
      const canvas = document.createElement('canvas');
      canvas.width = Math.round(img.width*scale); canvas.height = Math.round(img.height*scale);
      const ctx = canvas.getContext('2d');
      ctx.drawImage(img,0,0,canvas.width,canvas.height);
      const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
      document.getElementById('buktiDataField').value = dataUrl;
      const prev = document.getElementById('buktiPreview');
      prev.src = dataUrl; prev.classList.remove('hidden');
      Actions.recalcCheckout();
    };
    img.src = ev.target.result;
  };
  reader.readAsDataURL(file);
};
Actions.recalcCheckout = function(){
  const kurir = document.getElementById('kurirSelect')?.value || 'JNE Reguler';
  const metodeEl = document.querySelector('input[name="metode"]:checked');
  const metode = metodeEl ? metodeEl.value : 'COD';
  const ongkir = ONGKIR[kurir] ?? 0;
  const admin = BIAYA_ADMIN[metode] ?? 0;
  const total = Cart.total() + ongkir + admin;
  const set = (id,val)=>{ const el=document.getElementById(id); if(el) el.textContent = val; };
  set('rOngkir', RP(ongkir)); set('rAdmin', RP(admin)); set('rTotal', RP(total));
};
Actions.toggleMetode = function(metode){
  const info = document.getElementById('metodeInfo');
  const bukti = document.getElementById('buktiWrap');
  if(!info || !bukti) return;
  Actions.recalcCheckout();
  if(PAYMENT_INFO[metode]){
    info.innerHTML = PAYMENT_INFO[metode];
    info.classList.remove('hidden');
    bukti.classList.remove('hidden');
  } else {
    info.classList.add('hidden');
    bukti.classList.add('hidden');
  }
};

function renderPesanan(app){
  const u = Session.currentUser();
  const list = Orders.all().filter(o=>o.userId===u.id).sort((a,b)=>b.tanggal.localeCompare(a.tanggal));
  const statusColor = { 'Menunggu Pembayaran':'bg-turmeric text-coffee','Diproses':'bg-blue-400 text-white','Dikemas':'bg-purple-400 text-white','Dikirim':'bg-fresh text-white','Selesai':'bg-coffee text-white','Dibatalkan':'bg-chili text-white' };
  const content = `
  <h1 class="font-display font-bold text-xl text-coffee mb-4">Riwayat Pesanan</h1>
  ${list.length===0? `<div class="bg-card rounded-2xl p-10 text-center shadow-stamp text-coffee-light">Belum ada pesanan.</div>` :
  list.map(o=>`
  <div class="bg-card rounded-2xl shadow-stamp p-5 mb-4">
    <div class="flex flex-wrap items-center justify-between gap-2 mb-3">
      <div><span class="font-bold text-coffee">${o.id}</span> <span class="text-xs text-coffee-light">• ${fmtDate(o.tanggal)}</span></div>
      <span class="text-xs font-bold px-3 py-1 rounded-full ${statusColor[o.status]||'bg-paper'}">${o.status}</span>
    </div>
    ${o.items.map(it=>`<div class="flex justify-between text-sm py-0.5"><span>${esc(it.nama)} x${it.qty}</span><span>${RP(it.harga*it.qty)}</span></div>`).join('')}
    <div class="flex justify-between font-bold text-chili mt-2 pt-2 border-t border-paper-dark"><span>Total</span><span>${RP(o.total)}</span></div>
    <div class="flex gap-2 mt-3">
      ${(o.status==='Menunggu Pembayaran' || o.status==='Diproses') ? `<button onclick="Actions.cancelOrder('${o.id}')" class="text-xs px-4 py-1.5 border-2 border-chili text-chili rounded-full font-semibold">Batalkan Pesanan</button>`:''}
    </div>
  </div>`).join('')}`;
  userShell(app, content, 'pesanan');
}
Actions.cancelOrder = function(id){
  const list = Orders.all();
  const o = list.find(x=>x.id===id);
  if(o && (o.status==='Menunggu Pembayaran' || o.status==='Diproses')){ o.status='Dibatalkan'; Orders.save(list); toast('Pesanan dibatalkan','info'); renderPesanan(document.getElementById('app')); }
};

