function renderAdminDashboard(app){
  const products = Products.all(), users = Users.all(), orders = Orders.all();
  const todayOrders = orders.filter(o=>o.tanggal===todayISO());
  const pendapatan = orders.filter(o=>o.status!=='Dibatalkan').reduce((s,o)=>s+o.total,0);
  const terlaris = [...products].sort((a,b)=>b.terjual-a.terjual).slice(0,5);
  const terbaruOrders = [...orders].sort((a,b)=>b.tanggal.localeCompare(a.tanggal)).slice(0,5);
  const content = `
  <div class="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
    ${[['Jumlah Produk',products.length,'🍪'],['Jumlah User',users.length,'👥'],['Pesanan Hari Ini',todayOrders.length,'📦'],['Pendapatan',RP(pendapatan),'💰']].map(([l,v,i])=>`
    <div class="bg-card rounded-2xl shadow-stamp p-4"><div class="text-2xl mb-1">${i}</div><div class="text-2xl font-display font-extrabold text-chili">${v}</div><div class="text-xs text-coffee-light font-semibold">${l}</div></div>`).join('')}
  </div>
  <div class="grid lg:grid-cols-3 gap-6">
    <div class="lg:col-span-2 bg-card rounded-2xl shadow-stamp p-5">
      <h3 class="font-display font-bold text-coffee mb-3">Grafik Penjualan (14 hari terakhir)</h3>
      <canvas id="chartSales" height="120"></canvas>
    </div>
    <div class="bg-card rounded-2xl shadow-stamp p-5">
      <h3 class="font-display font-bold text-coffee mb-3">Produk Terlaris</h3>
      ${terlaris.map(p=>`<div class="flex items-center gap-2 justify-between py-1.5 text-sm border-b border-paper last:border-0"><span class="flex items-center gap-2 min-w-0"><span class="w-9 h-9 rounded-lg overflow-hidden shrink-0">${productMedia(p,'w-9 h-9','text-lg')}</span><span class="truncate">${esc(p.nama)}</span></span><b class="text-chili shrink-0">${p.terjual}</b></div>`).join('')}
    </div>
  </div>
  <div class="bg-card rounded-2xl shadow-stamp p-5 mt-6">
    <h3 class="font-display font-bold text-coffee mb-3">Pesanan Terbaru</h3>
    <div class="overflow-x-auto"><table class="w-full text-sm">
      <thead><tr class="text-left text-coffee-light border-b border-paper"><th class="py-2">ID</th><th>Tanggal</th><th>Total</th><th>Status</th></tr></thead>
      <tbody>${terbaruOrders.map(o=>`<tr class="border-b border-paper last:border-0"><td class="py-2">${o.id}</td><td>${fmtDate(o.tanggal)}</td><td>${RP(o.total)}</td><td>${o.status}</td></tr>`).join('')}</tbody>
    </table></div>
  </div>`;
  adminShell(app, content, 'admin');

  const days = [...Array(14)].map((_,i)=>{ const d=new Date(); d.setDate(d.getDate()-(13-i)); return d.toISOString().slice(0,10); });
  const data = days.map(d=>orders.filter(o=>o.tanggal===d && o.status!=='Dibatalkan').reduce((s,o)=>s+o.total,0));
  const ctx = document.getElementById('chartSales');
  chartRegistry.sales = new Chart(ctx, {
    type:'line',
    data:{ labels: days.map(d=>fmtDate(d)), datasets:[{ label:'Pendapatan', data, borderColor:'#C1440E', backgroundColor:'rgba(193,68,14,0.15)', fill:true, tension:.35 }] },
    options:{ plugins:{legend:{display:false}}, scales:{ y:{ ticks:{ callback:v=>RP(v) } } } }
  });
}

