Actions.openProductForm = function(id){
  const p = id ? Products.find(id) : null;
  const cats = Categories.all();
  openModal(`
  <form onsubmit="return Actions.saveProduct(event, ${id||'null'})" class="p-6 flex flex-col gap-3">
    <h2 class="font-display font-bold text-lg text-coffee mb-1">${p?'Edit':'Tambah'} Produk</h2>
    <input required name="nama" value="${p?esc(p.nama):''}" placeholder="Nama Produk" class="border-2 border-paper-dark rounded-xl px-4 py-2 focus:border-chili outline-none">
    <select required name="kategoriId" class="border-2 border-paper-dark rounded-xl px-4 py-2">${cats.map(c=>`<option value="${c.id}" ${p&&p.kategoriId==c.id?'selected':''}>${esc(c.nama)}</option>`).join('')}</select>
    <div class="grid grid-cols-2 gap-3">
      <input required type="number" name="harga" value="${p?p.harga:''}" placeholder="Harga" class="border-2 border-paper-dark rounded-xl px-4 py-2">
      <input required type="number" name="stok" value="${p?p.stok:''}" placeholder="Stok" class="border-2 border-paper-dark rounded-xl px-4 py-2">
    </div>
    <div class="grid grid-cols-2 gap-3">
      <input required type="number" name="berat" value="${p?p.berat:''}" placeholder="Berat (gram)" class="border-2 border-paper-dark rounded-xl px-4 py-2">
      <select name="halal" class="border-2 border-paper-dark rounded-xl px-4 py-2"><option value="true" ${p&&p.halal?'selected':''}>Halal</option><option value="false" ${p&&!p.halal?'selected':''}>Belum Bersertifikat</option></select>
    </div>
    <input name="komposisi" value="${p?esc(p.komposisi):''}" placeholder="Komposisi" class="border-2 border-paper-dark rounded-xl px-4 py-2">
    <textarea name="deskripsi" placeholder="Deskripsi Produk" class="border-2 border-paper-dark rounded-xl px-4 py-2">${p?esc(p.deskripsi):''}</textarea>
    <div class="grid grid-cols-2 gap-3">
      <div><label class="text-xs text-coffee-light">Tanggal Produksi</label><input type="date" name="tglProduksi" value="${p?p.tglProduksi:todayISO()}" class="w-full border-2 border-paper-dark rounded-xl px-4 py-2"></div>
      <div><label class="text-xs text-coffee-light">Kedaluwarsa</label><input type="date" name="expired" value="${p?p.expired:todayISO()}" class="w-full border-2 border-paper-dark rounded-xl px-4 py-2"></div>
    </div>
    <div>
      <label class="text-xs text-coffee-light">Foto Produk</label>
      <div class="flex items-center gap-3 mt-1">
        <img id="fotoPreview" src="${p&&p.gambar?p.gambar:''}" class="w-20 h-20 object-cover rounded-xl border-2 border-paper-dark ${p&&p.gambar?'':'hidden'}">
        <input type="file" name="fotoFile" id="fotoFileInput" accept="image/*" onchange="Actions.handleFotoUpload(event)" class="text-sm flex-1">
        <button type="button" onclick="Actions.removeFotoPreview()" class="text-xs text-chili font-semibold whitespace-nowrap">Hapus Foto</button>
      </div>
      <p class="text-xs text-coffee-light mt-1">Upload foto asli produk (JPG/PNG) agar tampil di halaman toko.</p>
      <input type="hidden" name="gambarData" id="gambarDataField" value="${p&&p.gambar?p.gambar:''}">
    </div>
    <div class="flex gap-3 mt-2">
      <button type="button" onclick="closeModal()" class="flex-1 border-2 border-coffee/30 rounded-xl py-2.5 font-semibold">Batal</button>
      <button class="flex-1 bg-chili text-white rounded-xl py-2.5 font-semibold">Simpan</button>
    </div>
  </form>`);
};
Actions.handleFotoUpload = function(e){
  const file = e.target.files[0];
  if(!file) return;
  const reader = new FileReader();
  reader.onload = function(ev){
    const img = new Image();
    img.onload = function(){
      const maxW = 600;
      const scale = Math.min(1, maxW/img.width);
      const canvas = document.createElement('canvas');
      canvas.width = Math.round(img.width*scale); canvas.height = Math.round(img.height*scale);
      const ctx = canvas.getContext('2d');
      ctx.drawImage(img,0,0,canvas.width,canvas.height);
      const dataUrl = canvas.toDataURL('image/jpeg', 0.82);
      document.getElementById('gambarDataField').value = dataUrl;
      const prev = document.getElementById('fotoPreview');
      prev.src = dataUrl; prev.classList.remove('hidden');
    };
    img.src = ev.target.result;
  };
  reader.readAsDataURL(file);
};
Actions.removeFotoPreview = function(){
  const field = document.getElementById('gambarDataField');
  const prev = document.getElementById('fotoPreview');
  const fileInput = document.getElementById('fotoFileInput');
  if(field) field.value = '';
  if(prev){ prev.src=''; prev.classList.add('hidden'); }
  if(fileInput) fileInput.value = '';
};
Actions.saveProduct = function(e, id){
  e.preventDefault();
  const f = new FormData(e.target);
  const list = Products.all();
  const data = {
    nama:f.get('nama'), kategoriId:Number(f.get('kategoriId')), harga:Number(f.get('harga')), stok:Number(f.get('stok')),
    berat:Number(f.get('berat')), komposisi:f.get('komposisi'), deskripsi:f.get('deskripsi'),
    halal:f.get('halal')==='true', tglProduksi:f.get('tglProduksi'), expired:f.get('expired'),
    gambar: f.get('gambarData') || null
  };
  if(id){ const p = list.find(x=>x.id==id); Object.assign(p,data); }
  else { list.push({ id: Math.max(0,...list.map(p=>p.id))+1, terjual:0, rating:4.5, badge:null, ...data }); }
  Products.save(list); closeModal(); toast('Produk berhasil disimpan'); renderAdminProduk(document.getElementById('app'));
  return false;
};
Actions.deleteProduct = function(id){
  openModal(`<div class="p-6 text-center">
    <p class="mb-4 font-semibold text-coffee">Hapus produk ini?</p>
    <div class="flex gap-3"><button onclick="closeModal()" class="flex-1 border-2 rounded-xl py-2">Batal</button>
    <button onclick="Products.save(Products.all().filter(p=>p.id!=${id})); closeModal(); toast('Produk dihapus','info'); renderAdminProduk(document.getElementById('app'));" class="flex-1 bg-chili text-white rounded-xl py-2">Hapus</button></div>
  </div>`);
};

