Actions.submitUbahPasswordAdmin = function(e){
  e.preventDefault();
  const f = new FormData(e.target);
  const errEl = document.getElementById('pwErr');
  const showErr = m=>{ errEl.textContent=m; errEl.classList.remove('hidden'); };
  const list = Admins.all();
  const a = list.find(x=>x.id===Session.currentAdmin().id);
  if(f.get('lama') !== a.password) return showErr('Password lama salah'), false;
  if(f.get('baru').length < 8) return showErr('Password baru minimal 8 karakter'), false;
  if(f.get('baru') !== f.get('konfirmasi')) return showErr('Konfirmasi password tidak sama'), false;
  a.password = f.get('baru');
  DB.set('as_admins', list);
  closeModal(); toast('Password berhasil diubah');
  return false;
};

