Actions.register = function(e){
  e.preventDefault();
  const f = new FormData(e.target);
  const nama=f.get('nama'), email=f.get('email'), hp=f.get('hp'), pass=f.get('password'), konf=f.get('konfirmasi');
  const errEl = document.getElementById('regErr');
  const showErr = m=>{ errEl.textContent=m; errEl.classList.remove('hidden'); };
  if(!nama||!email||!hp||!pass||!konf) return showErr('Semua field wajib diisi'), false;
  if(Users.findByEmail(email)) return showErr('Email sudah digunakan'), false;
  if(pass.length<8) return showErr('Password minimal 8 karakter'), false;
  if(pass!==konf) return showErr('Password dan Konfirmasi tidak sama'), false;
  const list = Users.all();
  list.push({ id: Math.max(0,...list.map(u=>u.id))+1, nama, email, hp, password:pass, alamat:'', kota:'', provinsi:'', kodepos:'', foto:'🙂', status:'aktif' });
  Users.save(list);
  toast('Registrasi berhasil! Silakan login');
  navigate('#/login');
  return false;
};
Actions.login = function(e){
  e.preventDefault();
  const f = new FormData(e.target);
  const u = Users.findByEmail(f.get('email'));
  const errEl = document.getElementById('loginErr');
  if(!u || u.password !== f.get('password')){ errEl.textContent='Email atau Password salah'; errEl.classList.remove('hidden'); return false; }
  if(u.status==='nonaktif'){ errEl.textContent='Akun dinonaktifkan, hubungi admin'; errEl.classList.remove('hidden'); return false; }
  Session.setUser(u.id); toast('Login berhasil, selamat datang '+u.nama.split(' ')[0]+'!'); navigate('#/home'); return false;
};
