Actions.toggleAdminDark = function(){
  const on = !DB.get('as_admin_dark', false);
  DB.set('as_admin_dark', on);
  document.documentElement.classList.toggle('admin-dark', on);
  route();
};
Actions.togglePw = function(btn){
  const wrap = btn.closest('.relative');
  const inp = wrap.querySelector('input');
  const openIcon = btn.querySelector('.eye-open');
  const closedIcon = btn.querySelector('.eye-closed');
  const showing = inp.type === 'text';
  inp.type = showing ? 'password' : 'text';
  openIcon.classList.toggle('hidden', !showing);
  closedIcon.classList.toggle('hidden', showing);
};

Actions.addToCart = function(id, qty, showToast){
  const p = Products.find(id);
  const current = (Cart.get().find(i=>i.productId==id)||{}).qty || 0;
  const finalQty = Math.min(qty, p.stok - current) || 0;
  if(finalQty<=0){ toast('Stok tidak mencukupi','err'); return; }
  Cart.add(id, finalQty);
  if(showToast) toast(p.nama+' ditambahkan ke keranjang');
  if(location.hash.startsWith('#/produk') || location.hash==='#/home') route();
};
Actions.buyNow = function(id, qty){
  Actions.addToCart(id, qty, false);
  navigate('#/checkout');
};
Actions.submitCheckout = function(e){
  e.preventDefault();
  const f = new FormData(e.target);
  const items = Cart.items();
  if(items.length===0){ toast('Keranjang kosong','err'); return false; }
  const metode = f.get('metode');
  const kurir = f.get('kurir');
  const buktiFile = e.target.bukti && e.target.bukti.files[0];
  const buktiData = f.get('buktiData') || null;
  const errEl = document.getElementById('checkoutErr');

  if(metode !== 'COD' && !buktiFile){
    if(errEl){ errEl.textContent = 'Anda belum mengirimkan bukti transfer. Pesanan tidak dapat dikonfirmasi.'; errEl.classList.remove('hidden'); }
    toast('Bukti transfer wajib diunggah untuk metode non-COD','err');
    return false;
  }

  const ongkir = ONGKIR[kurir] ?? 0;
  const biayaAdmin = BIAYA_ADMIN[metode] ?? 0;
  const total = Cart.total() + ongkir + biayaAdmin;
  // COD: langsung Diproses. Non-COD: bukti sudah wajib ada, status Menunggu Pembayaran sampai admin verifikasi di halaman Pembayaran (Terima -> Diproses).
  const statusAwal = (metode === 'COD') ? 'Diproses' : 'Menunggu Pembayaran';

  const order = {
    id:'ORD-'+uid(), userId:Session.currentUser().id, tanggal: todayISO(),
    items: items.map(i=>({productId:i.productId, nama:i.product.nama, harga:i.product.harga, qty:i.qty})),
    ongkir, biayaAdmin, total, nama:f.get('nama'), alamat:f.get('alamat'), kota:f.get('kota'), provinsi:f.get('provinsi'),
    kodepos:f.get('kodepos'), hp:f.get('hp'), kurir, metode,
    bukti: metode!=='COD' ? (buktiFile?.name || null) : null,
    buktiData: metode!=='COD' ? buktiData : null,
    status: statusAwal
  };
  const list = Orders.all(); list.push(order); Orders.save(list);
  // reduce stock, increase terjual
  const prods = Products.all();
  items.forEach(i=>{ const p = prods.find(x=>x.id===i.productId); if(p){ p.stok = Math.max(0,p.stok-i.qty); p.terjual += i.qty; } });
  Products.save(prods);
  Cart.clear();
  openModal(`<div class="p-8 text-center">
    <div class="text-5xl mb-3">🎉</div>
    <h2 class="font-display font-bold text-xl text-coffee mb-2">Pesanan Berhasil Dibuat!</h2>
    <p class="text-sm text-coffee-light mb-5">ID Pesanan: <b>${order.id}</b></p>
    <button onclick="closeModal(); navigate('#/pesanan')" class="px-6 py-2.5 bg-chili text-white rounded-full font-semibold">Lihat Pesanan</button>
  </div>`);
  return false;
};

Actions.updateProfil = function(e){
  e.preventDefault();
  const f = new FormData(e.target);
  const list = Users.all(); const u = list.find(x=>x.id===Session.currentUser().id);
  ['nama','hp','alamat','kota','provinsi'].forEach(k=>u[k]=f.get(k));
  Users.save(list); toast('Profil berhasil diperbarui'); renderProfil(document.getElementById('app'));
  return false;
};
Actions.changePassword = function(e){
  e.preventDefault();
  const f = new FormData(e.target);
  const list = Users.all(); const u = list.find(x=>x.id===Session.currentUser().id);
  const errEl = document.getElementById('pwErr');
  if(u.password !== f.get('lama')){ errEl.textContent='Password lama salah'; errEl.classList.remove('hidden'); return false; }
  if(f.get('baru').length<8){ errEl.textContent='Password baru minimal 8 karakter'; errEl.classList.remove('hidden'); return false; }
  u.password = f.get('baru'); Users.save(list); toast('Password berhasil diubah'); renderProfil(document.getElementById('app'));
  return false;
};